public void validateSubType(DeserializationContext ctxt, JavaType type) throws JsonMappingException {

    if (type.getRawClass() == null || type.getRawClass().isInterface()) {
        return;
    }

    if (type.getRawClass().getName().startsWith(PREFIX_SPRING)) {

        for (Class<?> cls = type.getRawClass(); (cls != null) && (cls != Object.class); cls = cls.getSuperclass()) {

            String name = cls.getSimpleName();

            if ("AbstractPointcutAdvisor".equals(name) || "AbstractApplicationContext".equals(name)) {
                return;
            }

        }
    }

    throw JsonMappingException.from(ctxt, String.format("Illegal type (%s) to deserialize: prevented for security reasons", type.getRawClass().getName()));
}
